SELECT accuracy
FROM decision_trees
WHERE accuracy > 0.8;

SELECT p_val1
FROM statistical_values
WHERE stat_id = 0;

SELECT p_val1, test_type
FROM statistical_values
WHERE p_val0 < 0.1;

SELECT feature_name
FROM genomic_features
WHERE feature_id = 1;

SELECT AVG(value) AS average_value
FROM study_features
WHERE feature_id = 1;

SELECT chromosome, AVG(start_position) AS avg_start_position
FROM genomic_features
GROUP BY chromosome;

SELECT value
FROM study_features
WHERE source = 'Predicted Data';

SELECT feature_name
FROM genomic_features
WHERE end_position = (SELECT MAX(end_position) FROM genomic_features);
